import array
import logging
import math
from typing import Optional

from .config import (
    AUDIO_DURATION_MS,
    AUDIO_FREQUENCY_HZ,
    AUDIO_SAMPLE_RATE,
    AUDIO_VOLUME,
)

log = logging.getLogger(__name__)

_sound_cache: Optional[object] = None
