def _init_pygame() -> bool:
    """Initialize pygame mixer. Returns True on success."""
    global _initialized
    if _initialized:
        return True
    try:
        import pygame
        pygame.mixer.pre_init(
            frequency=AUDIO_SAMPLE_RATE,
            size=-16,
            channels=1,
            buffer=512,
        )
        pygame.mixer.init()
        _initialized = True
        return True
    except Exception:
        log.exception("Failed to initialize pygame.mixer")
